const theme = {
  // Revert to the professional palette requested earlier
  primary: '#4a91af', // new primary per user request
  secondary: '#cdcec9', // neutral soft surface
  // reaction colors
  success: '#10B981',
  danger: '#EF4444',
  // Button tokens: neutral rectangular buttons and pill (oval) buttons
  neutralButton: '#e2e3e6', // rectangular action buttons (Join/Create/Notes/Calendar)
  pill: '#c8d1ff', // oval/pill buttons
  // Text colors
  text: '#000000', // default text black
  textPrimary: '#000000', // headings
  textSecondary: '#64748B', // supporting/details
  buttonText: '#000000',
  // Background
  background: '#f3f2ed'
};

export default theme;
